```java
@Component
public class CacheInvalidationHandler {
    private final CacheManager cm;
    CacheInvalidationHandler(CacheManager c) { cm=c; }

    public void onInvalidation(String message, String channel) {
        // channel: 'cache.invalidate.products'
        // message: 'P001'
        String cacheName = channel.substring(channel.lastIndexOf('.')+1);
        Cache cache = cm.getCache(cacheName);
        if (cache != null) cache.evict(message);
        System.out.println("[PubSub] Evicted " + message + " from " + cacheName);
    }
}

@Service
public class ProductPublisher {
    private final RedisTemplate<String,String> redis;
    ProductPublisher(RedisTemplate<String,String> r) { redis=r; }

    public void notifyInvalidation(String productId) {
        redis.convertAndSend("cache.invalidate.products", productId);
    }
}
